{ title: "Winkelen voor een cadeau", scene: "Je bent op een markt in Florence. Je zoekt een klein handgemaakt cadeau en vraagt naar de prijs.", lines: [{ who: "you", it: "Buongiorno, sto cercando un regalo.", nl: "Goedemorgen, ik zoek een cadeau." }, { who: "them", it: "Certo, per chi è?", nl: "Zeker, voor wie is het?" }, { who: "you", it: "Per mia sorella.", nl: "Voor mijn zus." }, { who: "them", it: "Abbiamo questa ceramica fatta a mano.", nl: "We hebben deze handgemaakte keramiek." }, { who: "you", it: "È molto bella.", nl: "Die is erg mooi." }, { who: "them", it: "Le piace questo colore?", nl: "Vindt u deze kleur mooi?" }, { who: "you", it: "Sì, mi piace molto.", nl: "Ja, ik vind hem erg mooi." }, { who: "them", it: "Costa quindici euro.", nl: "Het kost vijftien euro." }, { who: "you", it: "Può fare meno?", nl: "Kunt u minder vragen?" }, { who: "them", it: "Posso fare dodici euro.", nl: "Ik kan twaalf euro doen." }, { who: "you", it: "Va bene, prendo questo.", nl: "Prima, ik neem dit." }, { who: "them", it: "Grazie.", nl: "Dank u." }] },
{ title: "Bij de apotheek", scene: "Je voelt je niet goed in Genua en gaat naar een apotheek. Je hebt hoofdpijn en wilt weten hoeveel medicijn je moet nemen.", lines: [{ who: "them", it: "Buongiorno, mi dica.", nl: "Goedemorgen, zegt u het maar." }, { who: "you", it: "Buongiorno, ho mal di testa.", nl: "Goedemorgen, ik heb hoofdpijn." }, { who: "them", it: "Ha anche febbre?", nl: "Heeft u ook koorts?" }, { who: "you", it: "No, solo mal di testa.", nl: "Nee, alleen hoofdpijn." }, { who: "them", it: "Le consiglio questa medicina.", nl: "Ik raad u dit medicijn aan." }, { who: "you", it: "Serve una ricetta?", nl: "Is er een recept nodig?" }, { who: "them", it: "No, non serve.", nl: "Nee, dat is niet nodig." }, { who: "you", it: "Quanto ne devo prendere?", nl: "Hoeveel moet ik ervan nemen?" }, { who: "them", it: "Una compressa dopo mangiato.", nl: "Eén tablet na het eten." }, { who: "you", it: "Va bene, grazie.", nl: "Prima, dank u." }, { who: "them", it: "Se non passa, chiami un dottore.", nl: "Als het niet overgaat, bel dan een dokter." }, { who: "you", it: "Certo, grazie mille.", nl: "Zeker, heel erg bedankt." }] },
{ title: "Smalltalk met een local", scene: "Je zit op een bankje in Bologna en raakt in gesprek met een local. Je praat over waar je vandaan komt en wat je van Italië vindt.", lines: [{ who: "you", it: "Ciao, posso sedermi qui?", nl: "Hallo, mag ik hier zitten?" }, { who: "them", it: "Certo, prego.", nl: "Zeker, gaat u gang." }, { who: "you", it: "Grazie, è una bella giornata.", nl: "Dank je, het is een mooie dag." }, { who: "them", it: "Sì, oggi c’è molto sole.", nl: "Ja, vandaag is er veel zon." }, { who: "you", it: "Sono qui in vacanza.", nl: "Ik ben hier op vakantie." }, { who: "them", it: "Di dove sei?", nl: "Waar kom je vandaan?" }, { who: "you", it: "Vengo dai Paesi Bassi.", nl: "Ik kom uit Nederland." }, { who: "them", it: "Ti piace l’Italia?", nl: "Vind je Italië leuk?" }, { who: "you", it: "Sì, mi piace moltissimo.", nl: "Ja, ik vind het geweldig." }, { who: "them", it: "Quale città preferisci?", nl: "Welke stad vind je het leukst?" }, { who: "you", it: "Bologna è molto interessante e tranquilla.", nl: "Bologna is erg interessant en rustig." }, { who: "them", it: "Sono contento, buona vacanza.", nl: "Dat doet me plezier, fijne vakantie." }] }
